# ====================================================================================
# FUNCIONES AUXILIARES PARA FILTRAR INDICADORES
# ====================================================================================
def get_indicadores(filtro=None):
    """
    Retorna la lista de indicadores, posiblemente filtrada
    
    Args:
        filtro: Puede ser una lista de nombres de columnas a filtrar
    
    Returns:
        Lista de tuplas (nombre_columna, funcion_sql)
    """
    if filtro is None:
        return INDICADORES
    
    # Filtrar por nombres de columna
    return [(col, func) for col, func in INDICADORES if col in filtro]

def get_indicadores_by_prefix(prefix):
    """
    Retorna indicadores que comienzan con un prefijo específico
    
    Args:
        prefix: Prefijo para filtrar (ej: 'NDQ3')
    
    Returns:
        Lista de tuplas (nombre_columna, funcion_sql)
    """
    return [(col, func) for col, func in INDICADORES if col.startswith(prefix)]

def get_indicadores_by_range(start, end):
    """
    Retorna indicadores en un rango numérico
    
    Args:
        start: Número inicial (ej: 29)
        end: Número final (ej: 40)
    
    Returns:
        Lista de tuplas (nombre_columna, funcion_sql)
    """
    result = []
    for col, func in INDICADORES:
        # Extraer el número del nombre (ej: 'NDQ29' -> 29)
        try:
            num = int(col.replace('NDQ', ''))
            if start <= num <= end:
                result.append((col, func))
        except ValueError:
            continue
    return result

